// Select rows that NEED a draft: have a topic, no caption yet, and are not
// already approved/published. Keeps the AI from re-writing approved copy.
const out = [];
for (const item of $input.all()) {
  const r = item.json;
  const status = String(r.status || '').toLowerCase();
  const approval = String(r.approval || '').toLowerCase();
  const hasTopic = String(r.topic || '').trim().length > 0;
  const hasCaption = String(r.caption || '').trim().length > 0;
  if (hasTopic && !hasCaption && approval !== 'approved' && status !== 'published') {
    out.push({ json: r });
  }
}
return out;

// Parse Claude's JSON reply and merge it back onto the original calendar row.
// Robust to code fences / stray text around the JSON object.
const out = [];
for (let i = 0; i < $input.all().length; i++) {
  const resp = $input.all()[i].json;
  const src = $('Select Rows Needing Drafts').all()[i]?.json || {};
  let text = '';
  try { text = resp?.content?.[0]?.text || ''; } catch (e) { text = ''; }
  let parsed = {};
  try {
    const m = text.match(/\{[\s\S]*\}/);
    parsed = m ? JSON.parse(m[0]) : {};
  } catch (e) { parsed = {}; }
  out.push({ json: {
    row_number: src.row_number,
    caption: parsed.caption || '',
    hashtags: parsed.hashtags || '',
    hook: parsed.hook || src.hook || '',
    status: parsed.caption ? 'Ready for Review' : 'Draft Failed',
    approval: src.approval || ''
  }});
}
return out;
